// C++ solution file
#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
	int solve(vector<int>& nums, string target) {
		for (int i = 0; i < nums.size() - target.size() + 1; i++) {
			bool isMatch = true;
			for (int j = 0; j < target.size(); j++) {
				if (nums[i + j] != target[j]) {
					isMatch = false; break;
				}
			}
			if (isMatch) return i;
		}
		return -1;
	}
};

